package ua.university.sms.service;
import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.CourseDtos.*;import ua.university.sms.model.entity.Course;import ua.university.sms.repository.*;import java.util.*;
@Service public class CourseService{private final CourseRepository repo;private final TeacherRepository teachers;public CourseService(CourseRepository repo,TeacherRepository teachers){this.repo=repo;this.teachers=teachers;}public Response create(Request r){Course c=new Course();apply(c,r);return dto(repo.save(c));}public Response get(Long id){return dto(find(id));}public List<Response> list(Long teacherId,Integer credits){List<Course> data=teacherId!=null?repo.findByTeacherId(teacherId):credits!=null?repo.findByCredits(credits):repo.findAll();return data.stream().map(this::dto).toList();}public Response update(Long id,Request r){Course c=find(id);apply(c,r);return dto(repo.save(c));}public void delete(Long id){repo.delete(find(id));}Course find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Course not found: "+id));}private void apply(Course c,Request r){c.setTitle(r.title());c.setCredits(r.credits());c.setSemester(r.semester());c.setTeacher(teachers.findById(r.teacherId()).orElseThrow(()->new NotFoundException("Teacher not found: "+r.teacherId())));}private Response dto(Course c){return new Response(c.getId(),c.getTitle(),c.getCredits(),c.getSemester(),c.getTeacher().getId(),c.getTeacher().getFullName());}}
